// Group all prompts by agent then stage
function groupPrompts(prompts) {
  const groups = {};
  prompts.forEach(p => {
    const agent = p.agent || 'build';
    const stage = p.stage;
    const key = agent + '/' + stage;
    if (!groups[key]) groups[key] = [];
    groups[key].push(p);
  });
  // Sort within each group by seq
  for (const key of Object.keys(groups)) {
    groups[key].sort((a, b) => a.seq - b.seq);
  }
  return groups;
}

